@implementation FeedbackTableViewCell

- (CGSize)bubbleDisplaySizeForImageSize:(CGSize)imageSize {
    CGFloat ratio = (imageSize.height > 0.0f) ? (imageSize.width / imageSize.height) : 0.0f;
    CGFloat fixedW = (ratio > 1.0f) ? ZOOM(220) : ZOOM(160);
    CGFloat maxW = [UIScreen mainScreen].bounds.size.width * 0.7f;
    CGFloat width = (ratio > 0.0f) ? MIN(fixedW, maxW) : ZOOM(160);
    CGFloat height = (ratio > 0.0f) ? (width / ratio) : ZOOM(180);
    return CGSizeMake(width, height);
}

- (void)updateImageConstraintsWithDisplaySize:(CGSize)displaySize {
    [self.messageImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.bubbleView).offset(ZOOM(6));
        if (self.isSenderFlag) {
            make.right.equalTo(self.bubbleView).offset(ZOOM(-6));
        } else {
            make.left.equalTo(self.bubbleView).offset(ZOOM(6));
        }
        make.width.mas_equalTo(displaySize.width);
        make.height.mas_equalTo(displaySize.height);
        make.bottom.equalTo(self.bubbleView).offset(ZOOM(-6));
    }];
}

- (void)updateBubbleConstraintsForImageMessage {
    [self.bubbleView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.contentView).offset(ZOOM(8));
        make.bottom.equalTo(self.contentView).offset(ZOOM(-8));
        make.width.lessThanOrEqualTo(self.contentView.mas_width).multipliedBy(0.72);
        if (self.isSenderFlag) {
            make.right.equalTo(self.avatarImageView.mas_left).offset(ZOOM(-10));
            make.left.equalTo(self.messageImageView.mas_left).offset(ZOOM(-6));
        } else {
            make.left.equalTo(self.avatarImageView.mas_right).offset(ZOOM(10));
            make.right.equalTo(self.messageImageView.mas_right).offset(ZOOM(6));
        }
    }];
}

- (instancetype)initWithStyle:(UITableViewCellStyle)style reuseIdentifier:(NSString *)reuseIdentifier {
    self = [super initWithStyle:style reuseIdentifier:reuseIdentifier];
    if (self) {
        self.selectionStyle = UITableViewCellSelectionStyleNone;
        self.backgroundColor = [UIColor clearColor];
        [self setupUI];
    }
