 - (NSArray<FeedbackModel *> *)mapFeedbackListFromData:(NSDictionary *)data {
    id listRaw = [self safeValueForKey:@"list" fromDictionary:data];
    NSArray *list = [listRaw isKindOfClass:NSArray.class] ? (NSArray *)listRaw : nil;
    NSMutableArray<FeedbackModel *> *result = [NSMutableArray arrayWithCapacity:list.count];
    if (list) {
        for (id item in list) {
            NSDictionary *m = [item isKindOfClass:NSDictionary.class] ? (NSDictionary *)item : nil;
            if (!m) { continue; }
            FeedbackModel *model = [self modelFromDict:m];
            if (model) {
                [result addObject:model];
            }
        }
    }
    return result;
}

