- (void)pullNewFeedbackWithAutomaticFrequency {
    NSParameterAssert([[NSOperationQueue currentQueue] isEqual:[NSOperationQueue mainQueue]]);
    [self pullNewFeedback];
    NSString *latestString = [self.messages lastObject].time;
    NSDate *latestDate = [self dateFromString:latestString];
    NSTimeInterval latestInterval = latestDate ? [[NSDate date] timeIntervalSinceDate:latestDate] : 0.0f;
    NSTimeInterval nextPullInterval = 0.0f;
    if (latestInterval < 60.0f) {
        nextPullInterval = 1.0f;
    } else if (latestInterval < 60.0f * 10) {
        nextPullInterval = 3.0f;
    } else if (latestInterval < 60.0f * 60) {
        nextPullInterval = 5.0f;
    } else {
        nextPullInterval = 10.0f;
    }
    __weak typeof(self) weakSelf = self;
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(nextPullInterval * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [weakSelf pullNewFeedbackWithAutomaticFrequency];
    });
}


- (void)pullNewFeedback {
    [[FeedbackManager sharedManager] pullLatestFeedbacksWithCount:NSIntegerMax completion:^(NSArray<FeedbackModel *> * _Nullable feedbacks, NSError * _Nullable error) {
        if (error) {
            NSLog(@"轮询客服最新消息失败：%@", error.localizedDescription);
            return;
        }
        if (feedbacks.count == 0) { return; }
        NSInteger startIndex = self.messages.count;
        [self.messages addObjectsFromArray:feedbacks];
        NSMutableArray<NSIndexPath *> *paths = [NSMutableArray arrayWithCapacity:feedbacks.count];
        for (NSInteger i = 0; i < feedbacks.count; i++) {
            [paths addObject:[NSIndexPath indexPathForRow:startIndex + i inSection:0]];
        }
        [self.tableView performBatchUpdates:^{
            [self.tableView insertRowsAtIndexPaths:paths withRowAnimation:UITableViewRowAnimationNone];
        } completion:^(BOOL finished) {
            [self ensureBottomVisibleWithRetries:5 animated:NO];
        }];
    }];
}

- (void)loadOlderIfNeeded {
    if (self.isLoadingOlder || !self.hasMoreHistory) { return; }
    CGFloat y = self.tableView.contentOffset.y;
    if (y > 0) { return; }
    [self loadOlderMessages];
}

- (void)loadOlderMessages {
    self.isLoadingOlder = YES;
    NSInteger fromId = self.messages.count > 0 ? self.messages.firstObject.msgId : 0;
    CGFloat beforeHeight = self.tableView.contentSize.height;
    [[FeedbackManager sharedManager] fetchRecentFeedbacksWithCount:10 from:fromId completion:^(NSArray<FeedbackModel *> * _Nullable feedbacks, NSError * _Nullable error) {
        self.isLoadingOlder = NO;
        if (error) { return; }
        if (feedbacks.count == 0) { self.hasMoreHistory = NO; return; }
        NSSet *existing = [NSSet setWithArray:[self.messages valueForKey:@"msgId"]];
        NSMutableArray<FeedbackModel *> *toInsert = [NSMutableArray array];
        for (FeedbackModel *m in feedbacks) {
            if (![existing containsObject:@(m.msgId)]) {
                [toInsert addObject:m];
            }
        }
        if (toInsert.count == 0) { return; }
        NSArray<FeedbackModel *> *sorted = [toInsert sortedArrayUsingComparator:^NSComparisonResult(FeedbackModel * _Nonnull a, FeedbackModel * _Nonnull b) {
            if (a.msgId < b.msgId) return NSOrderedAscending;
            if (a.msgId > b.msgId) return NSOrderedDescending;
            return NSOrderedSame;
        }];
        NSIndexSet *indexes = [NSIndexSet indexSetWithIndexesInRange:NSMakeRange(0, sorted.count)];
        [self.messages insertObjects:sorted atIndexes:indexes];
        [self.tableView reloadData];
        CGFloat afterHeight = self.tableView.contentSize.height;
        CGFloat delta = afterHeight - beforeHeight;
        CGPoint offset = self.tableView.contentOffset;
        offset.y += delta;
        [self.tableView setContentOffset:offset animated:NO];
    }];
}

- (NSDate *)dateFromString:(NSString *)s {
    if (![s isKindOfClass:NSString.class] || s.length == 0) {
        return nil;
    }
    static NSDateFormatter *fmt;
    static dispatch_once_t once;
    dispatch_once(&once, ^{
        fmt = [[NSDateFormatter alloc] init];
        fmt.locale = [NSLocale localeWithLocaleIdentifier:@"en_US_POSIX"];
        NSTimeZone *tz = [NSTimeZone timeZoneWithName:@"Asia/Shanghai"];
        fmt.timeZone = tz ?: [NSTimeZone timeZoneForSecondsFromGMT:8*3600];
        fmt.dateFormat = @"yyyy-MM-dd HH:mm:ss";
    });
    return [fmt dateFromString:s];
}

