#import "ServiceMsgModel.h"

@implementation ServiceMsgModel

+ (NSMutableArray<ServiceMsgModel *> *)allMsgs {
    static NSMutableArray *msgs = nil;

    if (msgs) {
        return msgs;
    }

    @synchronized (self) {
        if (!msgs) {
            msgs = [NSMutableArray array];

            // 尝试从文件加载
            NSArray *savedMsgs = [NSArray arrayWithJsonFile:[self filePath] elementClass:[ServiceMsgModel class]];
            if (savedMsgs) {
                [msgs addObjectsFromArray:savedMsgs];
            }
        }
    }

    return msgs;
}

- (instancetype)initWithContent:(NSString *)content type:(MessageTypeS)type cellHeight:(CGFloat) cellHeight {
    self = [super init];
    if (self) {
        _content = content;
        _type = type;
        _cellHeight = cellHeight;
    }
    return self;
}

#pragma mark - NSCoding

- (void)encodeWithCoder:(NSCoder *)coder {
    [coder encodeObject:self.content forKey:@"content"];
    [coder encodeInt:self.type forKey:@"type"];
    [coder encodeFloat:self.cellHeight forKey:@"cellHeight"];
}

- (nullable instancetype)initWithCoder:(NSCoder *)coder {
    if (self = [super init]) {
        _content = [coder decodeObjectForKey:@"content"];
        _type = (MessageTypeS)[coder decodeIntForKey:@"type"];
        _cellHeight = [coder decodeFloatForKey:@"cellHeight"];
    }
    return self;
}

+ (void)saveMsgs {
    [[ServiceMsgModel allMsgs] writeToJsonFile:[self filePath]];
}

+ (void)addMsg:(ServiceMsgModel *)Msg {
    [[ServiceMsgModel allMsgs] addObject:Msg];
    [self saveMsgs];
}

+ (void)clearMsgs {
    [[ServiceMsgModel allMsgs] removeAllObjects];
    [self saveMsgs];
}

#pragma mark - Private
+ (NSString *)filePath {
    return [NSFileManager documentFilePathWithName:@"Msgs.json"];
}
@end

